var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"흐음~?","JPN":"ふ～ん？","ENG":"Hmm?","TWN":"嗯~?"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"누군가 했더니 선배잖아? 그렇게 차려 입으니까 몰라보겠는데?","JPN":"誰かと思ったら先輩じゃない？　素敵な服を着てるから見違えたわ。","ENG":"Shiyoon, I almost didn't recognize you. You look different, dressed up like that.","TWN":"我還以為是誰呢，原來是前輩啊？穿成那樣我都認不出來了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"아. 오셨네요, 서윤 양. 서윤 양도 옷이 잘 어울리는데요.","JPN":"アオイさんもいらしたのですね。そのお洋服もお似合いです。","ENG":"Ah, you came, Seo Yoon. You look nice, too.","TWN":"啊，妳來了，徐芸小姐，衣服很適合妳呢。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"회사에서도 그렇게 좀 입고 다니지. 선배 아니어도 펜릴 소대가 좀 우중충한 편이잖아?","JPN":"普段の服もそういうのに変えればいいのに。フェンリル小隊ってみんな地味な服ばっか着てるから。","ENG":"You should dress up more often. You don't have to add to the Fenrir Squad's gloomy image.","TWN":"你在公司也這麼穿多好，即使沒有前輩，芬里爾小隊就已經夠陰沉的了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"하하. 충고는 감사하지만 아시다시피 같은 옷을 꽤 사 둔 편이라서요.","JPN":"ハハハ、ご忠告は感謝しますが、ご存知のとおり同じ服を大量に買っておいたので。","ENG":"Hah hah. Thank you for your advice, but as you know, I bought many duplicates of the same clothes I wear.","TWN":"哈哈，謝謝妳的建議，不過妳也知道我已經買了很多相同的衣服。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"그나저나 다른 분들은 같이 안 오셨나요?","JPN":"それより、他の皆さんは？","ENG":"By the way, didn't you come with the others?","TWN":"話說，其他人怎麼沒來？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"비용 문제 때문에 우리 소대 중에선 내가 대표로 초대장을 받았거든.","JPN":"忘年会の予算の問題で、アルト小隊では私だけ招待されたの。","ENG":"No. I came alone to represent my squad because of the expenses.","TWN":"因為費用問題，我們小隊就派我一個人作為代表參加晚會。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"회사 사정이 나아져도 이런 건 변하질 않는다니까.","JPN":"最近は会社の事情も良くなったって聞いたけど、こういうところは変わらないのね。","ENG":"Some things never change, no matter how well our company's doing.","TWN":"即使公司的情況有所好轉，但這方面還是沒辦法啊。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그러는 선배는? 펜릴 소대도 선배 혼자만 온 거 아냐?","JPN":"ところで先輩は？　フェンリル小隊も先輩一人だけ？","ENG":"What about you? You're the only one from Fenrir Squad?","TWN":"前輩你呢？你怎麼也是一個人？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"미나 양과 스승님은 부사장님의 특명으로 연말 경비 업무에 투입되셨답니다.","JPN":"ミナさんと師匠は副社長の特命で、年末警備任務に投入されました。","ENG":"Mina and the Master are on year-end security duty. The Vice President's orders.","TWN":"米娜和師父收到副總的命令，投入到年末警備業務了。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"누군가 돈을 쓰면 누군가는 돈을 벌어야 하는 법이라고 부사장님께서 말씀하셨거든요.","JPN":"副社長曰く、誰かが金を使う時は、他の誰かが金を稼がなければならないそうです。","ENG":"She said if someone spends money, someone has to make up for it.","TWN":"副總說，有人花錢，就有人得去賺錢。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그런데도 선배는 용케 빠졌네?","JPN":"先輩は運良く任務から外されたのね？","ENG":"How did you manage to get out?","TWN":"前輩，你怎麼不去賺錢？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"아, 전 겨울이 되면 왼쪽 새끼발가락 두 번째 마디가 아픈 지병이 있어서요.","JPN":"そうですね、僕は冬になると左足の小指の第二関節が痛む持病があるんです。","ENG":"Oh. I have chronic pain in the second knuckle of my left pinky toe that comes back every winter.","TWN":"啊，一到冬天，我左腳小腳趾的第二個關節就很疼。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"아무래도 과로는 무리일 것 같아서 휴가계를 쓰고 빠져 나왔죠.","JPN":"そんなわけで無理は禁物なため、休暇を取りました。","ENG":"I couldn't risk aggravating it, so I took sick leave.","TWN":"不能過度勞累，所以就提交了休假申請書。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......그거 부사장님 결재 난 거 맞아?","JPN":"その事情……副社長も知ってるの？","ENG":"Did you get the Vice President's approval?","TWN":"……你確定副總批准了你的申請書嗎？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"하하. 이건 서윤 양에게만 특별히 말씀드리는 건데, 부사장님의 보안 계정 비밀번호는 <color=#ffd34c>LSYSTRIKE1234HOT</color>입니다.","JPN":"ハハ、これはアオイさんにだけ特別に教えますが、\\n副社長のセキュリティアカウントのパスワードは<color=#ffd34c>KZNSTRIKE1234HOT</color>です。","ENG":"Hah hah. Just between you and me, the Vice President's security account password is <color=#ffd34c>LSYSTRIKE1234HOT</color>.","TWN":"哈哈，偷偷告訴妳，副總的安保帳號密碼是<color=#ffd34c>LSYSTRIKE1234HOT</color>。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"무슨 뜻인지는 모르겠지만요.","JPN":"どういう意味かはわかりませんが。","ENG":"I don't know what that means, though.","TWN":"雖然我不知道密碼有什麼意義。"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"흐음~ 대단한데? 어떻게 알아낸 거야?","JPN":"やるじゃない。どうやって調べたの？","ENG":"Oh, that's impressive! How did you find out?","TWN":"嗯哼~了不起啊？你是怎麼知道的？"},"stage":{"bg":"X_MAS_ROOM","slots":{"L":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};